  IF v_lesson_id IS NULL THEN
    INSERT INTO lessons (course_id, module_id, institution_id, title, order_index, content_type, content_url, is_required)
    VALUES ('823fe330-1df4-42ee-89af-d7df079958f5', '9a681ce2-e300-404e-be2c-a081e6795ade', '725f40e5-a317-4b8f-80b8-1df6cf3bbe2a', 'Untitled lesson', 4, 'blocks', '', true)
    RETURNING id INTO v_lesson_id;
  END IF;
  DELETE FROM lesson_blocks WHERE lesson_id = v_lesson_id;
  INSERT INTO lesson_blocks (lesson_id, institution_id, block_type, title, data, order_index, is_visible, version, settings)
  VALUES (v_lesson_id, '725f40e5-a317-4b8f-80b8-1df6cf3bbe2a', 'rich_text', 'Introduction to the Effective Advocacy Module', '{"html":"<p>In this module, learners will learn the fundamentals of becoming effective patient advocates; how to advocate with hospitals and governments, and how to personalize the knowledge to their region and country.</p>\n<img src=\"fit_content_assets/advocacy_images_p3z2nc.jpg\" alt=\"\" />\n<p><strong>Author: </strong>Lanre Tunji-Ajayi MSM</p><p><strong>Recognition</strong>: We recognize the video contributions of Ekawat Suwantaroj, Nehal Dhingra, and Eunice Owino.</p><p><strong>Image credits: </strong><a target=\"_blank\" rel=\"noopener noreferrer nofollow\" href=\"http://www.freepic\">www.freep</a>ik.com</p>","media":[{"type":"image","url":"fit_content_assets/advocacy_images_p3z2nc.jpg"}],"mode":"scrolling"}'::jsonb, 0, true, 1, '{}'::jsonb);
  INSERT INTO lesson_blocks (lesson_id, institution_id, block_type, title, data, order_index, is_visible, version, settings)
  VALUES (v_lesson_id, '725f40e5-a317-4b8f-80b8-1df6cf3bbe2a', 'rich_text', 'Lesson 1: Disclaimer', '{"html":"<p>The Capacity Building Curriculum (\"Curriculum\") may be used strictly for educational, non-commercial purposes. By permitting such use, the Global Action Network for Sickle Cell &amp; Other Inherited Blood Disorders (GANSID) does not grant any broader license or waive any of its or any contributor''s rights under copyright or otherwise at law.</p>\n<img src=\"fit_content_assets/an_eduation_trainer_mo2lt7_s4udnl.jpg\" alt=\"\" />\n<p></p>\n<p>This Curriculum has been developed as an educational tool for patient organizations and advocates.  The GANSID assumes no liability for any inaccurate or incomplete information contained in this Curriculum, nor any actions taken in reliance thereon. You assume full responsibility for the use of any information provided. The information contained herein has been supplied by individual subject matter contributors without verification by us. </p>\n<p>The information is provided \"AS IS\" and GANSID assumes no obligation to update the information or advise on further developments concerning the topics mentioned. GANSID will not be responsible or liable in any way for the accuracy, relevancy, or copyright compliance of the material contained in this Curriculum. </p>\n<p>By viewing and using any information derived from the Curriculum, you hereby waive any claims, causes of action, and demands, whether in tort or contract, against GANSID (including its content creators, staff, directors, officers, and agents) and contributors, in any way related to use of the Curriculum or the information derived from it.</p>","media":[{"type":"image","url":"fit_content_assets/an_eduation_trainer_mo2lt7_s4udnl.jpg"}],"mode":"scrolling"}'::jsonb, 1, true, 1, '{}'::jsonb);
  INSERT INTO lesson_blocks (lesson_id, institution_id, block_type, title, data, order_index, is_visible, version, settings)
  VALUES (v_lesson_id, '725f40e5-a317-4b8f-80b8-1df6cf3bbe2a', 'rich_text', 'Lesson 2: Learning Objectives', '{"html":"<p>Following completion of this module, learners will be able to:</p><ul><li><p>Improve their advocacy work with their hospitals, health systems, and government</p></li><li><p>Support patients and families they serve to become better self-advocates</p></li><li><p>Better understand ethical considerations in advocacy</p></li><li><p>Apply critical thinking skills from the knowledge gained in this course module to their locality or country.</p></li></ul>\n<img src=\"fit_content_assets/Group_work_whd5ix.jpg\" alt=\"\" />\n<p></p>","media":[{"type":"image","url":"fit_content_assets/Group_work_whd5ix.jpg"}],"mode":"scrolling"}'::jsonb, 2, true, 1, '{}'::jsonb);
  INSERT INTO lesson_blocks (lesson_id, institution_id, block_type, title, data, order_index, is_visible, version, settings)
  VALUES (v_lesson_id, '725f40e5-a317-4b8f-80b8-1df6cf3bbe2a', 'rich_text', ' Context to the Fundamentals of Advocacy ', '{"html":"<p>Context to the Fundamentals of Advocacy Module</p>\n<p>Whether operating in a low, medium, or high-resource environment, most advocates and organizations supporting individuals and families affected by inherited blood disorders are typically motivated by a personal connection to the disease. This ensures a passionate commitment, but may not provide access to the opportunities or resources needed for effective advocacy.</p>\n<img src=\"fit_content_assets/advocacy_image-4_nxaum3.jpg\" alt=\"\" />\n<p></p>\n<p>With the GANSID''s capacity-building initiative, we hope to strengthen the advocacy skill sets of the patient organizations serving the inherited blood disorders communities through training, mentorship, and cross-disease collaborations. </p>\n<p>Through this program, the GANSID will empower its member organizations to be able to work with their health systems and governments to advance care, treatment, research, capacity building, and education in regions of the world facing acute challenges due to underdeveloped healthcare systems, poverty, and a lack of disease awareness among patient population.</p>","media":[{"type":"image","url":"fit_content_assets/advocacy_image-4_nxaum3.jpg"}],"mode":"scrolling"}'::jsonb, 3, true, 1, '{}'::jsonb);
  INSERT INTO lesson_blocks (lesson_id, institution_id, block_type, title, data, order_index, is_visible, version, settings)
  VALUES (v_lesson_id, '725f40e5-a317-4b8f-80b8-1df6cf3bbe2a', 'rich_text', 'Advocacy vs Effective Advocacy?', '{"html":"<p></p>\n<p>Advocacy is an act of supporting or promoting a cause, idea, or policy to bring about change or influence decisions within political, economic, social systems and institutions.</p>\n<p>Effective advocacy is the art of targeting and accomplishing an advocacy action. It utilizes strategic planning and targeted action.</p>\n<img src=\"fit_content_assets/advocacy-colored_woman_with_speaker_wqnuj2.jpg\" alt=\"\" />\n<p>Skills: Effective advocacy requires a range of skills, including networking, public speaking, persuasive writing, and critical thinking.</p>\n<p>In addition, active listening, empathy, and the ability to build relationships and collaborate with others are also important skills for advocates.</p>\n<p>Advocacy Platforms: Various platforms, such as public speaking, letter-writing campaigns, lobbying events, and social media, can be used for advocacy. </p>\n<p></p>","media":[{"type":"image","url":"fit_content_assets/advocacy-colored_woman_with_speaker_wqnuj2.jpg"}],"mode":"scrolling"}'::jsonb, 4, true, 1, '{}'::jsonb);
  INSERT INTO lesson_blocks (lesson_id, institution_id, block_type, title, data, order_index, is_visible, version, settings)
  VALUES (v_lesson_id, '725f40e5-a317-4b8f-80b8-1df6cf3bbe2a', 'rich_text', 'Lesson 5: Types of Advocacy', '{"html":"<p>In this lesson, we will address:</p><ol><li><p>Individual - Driven Advocacy</p></li><li><p>Patient Organization - Driven Advocacy</p></li></ol>\n<img src=\"fit_content_assets/writing_higx0s.jpg\" alt=\"\" />\n<p></p><p></p>\n<p></p>\n<p></p>\n<p></p>","media":[{"type":"image","url":"fit_content_assets/writing_higx0s.jpg"}],"mode":"scrolling"}'::jsonb, 5, true, 1, '{}'::jsonb);
  INSERT INTO lesson_blocks (lesson_id, institution_id, block_type, title, data, order_index, is_visible, version, settings)
  VALUES (v_lesson_id, '725f40e5-a317-4b8f-80b8-1df6cf3bbe2a', 'image_gallery', '', '{"images":[{"url":"fit_content_assets/advocacy-line-inverted-icon-free-vector_u8n3zu.jpg","caption":"<p style=\"text-align: left\"><strong>Overview:</strong></p><p style=\"text-align: left\">Successful advocacy means knowing what needs to be accomplished and being <u>realistic</u> in your expectations. It requires careful planning and strategic thinking. We have provided six ingredients to successful advocacy in this lesson to help you execute your advocacy initiative effectively.</p>"}],"mode":"slider"}'::jsonb, 6, true, 1, '{}'::jsonb);
  INSERT INTO lesson_blocks (lesson_id, institution_id, block_type, title, data, order_index, is_visible, version, settings)
  VALUES (v_lesson_id, '725f40e5-a317-4b8f-80b8-1df6cf3bbe2a', 'rich_text', 'Encountering Advocacy Challenges', '{"html":"<p>Your advocacy efforts may be met with various challenges, including:</p><ul><li><p>Resistance from those in power whereby, advocates may encounter indifference, opposition, skepticism, or apathy from decision-makers</p></li><li><p>Inability to maintain momentum and sustain the advocacy efforts</p></li><li><p> Lack of public and decision-makers'' awareness of the issue</p></li><li><p> Limited resources (human and financial) and competing priorities</p></li></ul>\n<img src=\"fit_content_assets/overcoming_challenge_2_yvv7lb.jpg\" alt=\"\" />\n<p></p>","media":[{"type":"image","url":"fit_content_assets/overcoming_challenge_2_yvv7lb.jpg"}],"mode":"scrolling"}'::jsonb, 7, true, 1, '{}'::jsonb);
  INSERT INTO lesson_blocks (lesson_id, institution_id, block_type, title, data, order_index, is_visible, version, settings)
  VALUES (v_lesson_id, '725f40e5-a317-4b8f-80b8-1df6cf3bbe2a', 'rich_text', 'Become a Patient Advocate', '{"html":"<p>Patient advocacy is a lifelong journey, requiring perseverance, resilience, and a commitment to making a positive difference in the lives of people affected by one or more disease(s).</p>\n<img src=\"fit_content_assets/become_an_advocate_dlzrei.jpg\" alt=\"\" />\n<p><strong>Who can become a patient advocate?</strong> </p><p>Anyone can become a patient advocate by first identifying a patient-related issue and taking action on it.</p><p>Joining advocacy organizations, attending workshops or training sessions, and volunteering for patient-related causes can provide valuable opportunities to learn and develop skills to become an effective patient advocate.</p>","media":[{"type":"image","url":"fit_content_assets/become_an_advocate_dlzrei.jpg"}],"mode":"scrolling"}'::jsonb, 8, true, 1, '{}'::jsonb);
  INSERT INTO lesson_blocks (lesson_id, institution_id, block_type, title, data, order_index, is_visible, version, settings)
  VALUES (v_lesson_id, '725f40e5-a317-4b8f-80b8-1df6cf3bbe2a', 'rich_text', 'Ethical Considerations in Patient Advocacy', '{"html":"<p>Patient advocacy should be conducted ethically, respecting the rights and dignity of all individuals involved.</p>\n<img src=\"fit_content_assets/ethical_considerations_egjaxz.jpg\" alt=\"\" />\n<p>A patient advocate must place the advocacy initiative ahead of any personal interest or personal gain, and disclose all facts in any situation where a potential conflict of interest may arise.</p>\n<p>A patient advocate should be:</p><ul><li><p>Transparent and honest,</p></li><li><p> Be accountable in their actions and communications,</p></li><li><p>Base advocacy efforts on accurate information and evidence.</p></li></ul><p></p>","media":[{"type":"image","url":"fit_content_assets/ethical_considerations_egjaxz.jpg"}],"mode":"scrolling"}'::jsonb, 9, true, 1, '{}'::jsonb);
  INSERT INTO lesson_blocks (lesson_id, institution_id, block_type, title, data, order_index, is_visible, version, settings)
  VALUES (v_lesson_id, '725f40e5-a317-4b8f-80b8-1df6cf3bbe2a', 'rich_text', 'GANSID- Bringing Us Together in Advocacy', '{"html":"<p></p>\n<img src=\"fit_content_assets/Roundtable-Lanre_sajqjl_wwadki.jpg\" alt=\"\" />\n<p>Before you complete this advocacy module, we hope to share a few patient advocacy stories with you, and we hope their stories will inspire you to greater work in your own country and region.</p>\n<p></p>\n<p></p>\n<p></p>","media":[{"type":"image","url":"fit_content_assets/Roundtable-Lanre_sajqjl_wwadki.jpg"}],"mode":"scrolling"}'::jsonb, 10, true, 1, '{}'::jsonb);
  INSERT INTO lesson_blocks (lesson_id, institution_id, block_type, title, data, order_index, is_visible, version, settings)
  VALUES (v_lesson_id, '725f40e5-a317-4b8f-80b8-1df6cf3bbe2a', 'cta', '', '{"action":"complete_lesson","text":"Nice work. You''ve completed this lesson.","button_label":"Exit Lesson"}'::jsonb, 11, true, 1, '{}'::jsonb); END $$;